import React, { useCallback, useEffect, useMemo, useState } from 'react';
import {  LIN_ERP_LIST_FILTER_LAYOUT,
  LinErpListFilterBar,

  Select,
  LinPageLayout,
  dispatchAppToast,
  useCatalogTableBusy,
  type LinListToolbarActionDef,
} from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { hrService } from '../../../services/ns/hrService';
import type { DepartmentDto, WorkTimeReportRow } from '../../../services/ns/models';
import { baoCaoCongPageLabels as labels } from '../../../constants/baoCaoCongPageLabels';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { useHrAttendancePermissions } from '../../../hooks/useHrPermissions';
import erp from '../../../styles/erpPage.module.css';

const TEST_ID = 'erp-bao-cao-cong';
const PAGE_ID = 'ns-bao-cao-cong';

const MONTH_OPTIONS = Array.from({ length: 12 }, (_, i) => ({
  value: String(i + 1),
  label: `T${i + 1}`,
}));
const YEAR_OPTIONS = [2025, 2026, 2027].map(y => ({ value: String(y), label: String(y) }));

const BaoCaoCongPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const perms = useHrAttendancePermissions();
  const now = new Date();
  const [reloadKey, setReloadKey] = useState(0);
  const [month, setMonth] = useState(now.getMonth() + 1);
  const [year, setYear] = useState(now.getFullYear());
  const [departmentId, setDepartmentId] = useState('');
  const [depts, setDepts] = useState<DepartmentDto[]>([]);
  const [rows, setRows] = useState<WorkTimeReportRow[]>([]);
  const [loading, setLoading] = useState(false);

  const refresh = useCallback(() => {
    setReloadKey(k => k + 1);
  }, []);

  useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => {
      hrService
        .getDepartments()
        .then(d => {
          if (!cancelled) setDepts(d);
        })
        .catch(() => {});
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, []);

  useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      hrService
        .getWorkTimeReport({ month, year, departmentId: departmentId || undefined })
        .then(data => {
          if (!cancelled) setRows(data);
        })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, {
              message: getApiErrorMessage(err, labels.loadError),
              type: 'error',
            });
          }
        })
        .finally(() => {
          if (!cancelled) setLoading(false);
        });
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, [dispatch, month, year, departmentId, reloadKey]);

  const totalOT = rows.reduce((s, r) => s + (r.overtimeHours ?? 0), 0);
  const avgRate = rows.length
    ? rows.reduce((s, r) => s + (r.attendanceRate ?? 0), 0) / rows.length
    : 0;

  const handleExport = useCallback(() => {
    const qs = new URLSearchParams({ month: String(month), year: String(year) });
    if (departmentId) qs.set('departmentId', departmentId);
    const a = document.createElement('a');
    a.href = `${import.meta.env.VITE_API_URL}/hr/attendance/work-time-report/export-excel?${qs}`;
    a.download = `ChamCong-T${month}-${year}.xlsx`;
    a.click();
  }, [month, year, departmentId]);

  const { showTableLoading } = useCatalogTableBusy(loading);

  const headerHint = useMemo(() => {
    if (rows.length === 0) return undefined;
    return `${rows.length} ${labels.summaryEmployees} · ${labels.summaryOvertime}: ${totalOT.toFixed(1)}h · ${labels.summaryAttendance}: ${avgRate.toFixed(1)}%`;
  }, [rows.length, totalOT, avgRate]);

  const toolbarActions = useMemo((): LinListToolbarActionDef[] => {
    const left: LinListToolbarActionDef[] = [
      {
        id: 'refresh',
        placement: 'left',
        action: 'refresh',
        visible: true,
        onClick: refresh,
        testId: `${TEST_ID}-toolbar-refresh-btn`,
      },
    ];
    if (!perms.canRead) return left;
    return [
      ...left,
      {
        id: 'export',
        placement: 'right',
        label: labels.exportAction,
        variant: 'secondary',
        visible: true,
        disabled: rows.length === 0,
        onClick: handleExport,
        testId: `${TEST_ID}-toolbar-export-btn`,
      },
    ];
  }, [refresh, perms.canRead, handleExport, rows.length]);

  const listFilters = useMemo(
    () => (
      <LinErpListFilterBar
        testIdPrefix={TEST_ID}
        onDateChange={() => {}}
        onSearch={refresh}
        searchAriaLabel="Tìm"
        loading={showTableLoading}
        leading={(
          <>
            <div data-testid={`${TEST_ID}-field-month`}>
              <Select
                label={labels.monthLabel}
                value={String(month)}
                onChange={e => setMonth(Number(e.target.value))}
                options={MONTH_OPTIONS}
                fullWidth
              />
            </div>
            <div data-testid={`${TEST_ID}-field-year`}>
              <Select
                label={labels.yearLabel}
                value={String(year)}
                onChange={e => setYear(Number(e.target.value))}
                options={YEAR_OPTIONS}
                fullWidth
              />
            </div>
            <div data-testid={`${TEST_ID}-field-dept`}>
              <Select
                label={labels.deptLabel}
                value={departmentId}
                onChange={e => setDepartmentId(e.target.value)}
                options={[
                  { value: '', label: labels.deptAll },
                  ...depts.map(d => ({ value: d.id, label: d.name })),
                ]}
                fullWidth
              />
            </div>
          </>
        )}
      />
    ),
    [month, year, departmentId, depts, refresh, showTableLoading],
  );

  const listBody =
    !showTableLoading && rows.length === 0 ? (
      <div className={erp.empty} data-testid={`${TEST_ID}-empty`}>
        <i className="fas fa-inbox" />
        <p>{labels.empty}</p>
      </div>
    ) : !showTableLoading ? (
      <div className={erp.tableWrapper}>
        <table className={erp.table} data-testid={`${TEST_ID}-table`}>
          <thead>
            <tr>
              <th>{labels.colCode}</th>
              <th>{labels.colName}</th>
              <th>{labels.colDept}</th>
              <th className={erp.colRight}>{labels.colWorkingDays}</th>
              <th className={erp.colRight}>{labels.colOvertime}</th>
              <th>{labels.colAttendance}</th>
            </tr>
          </thead>
          <tbody>
            {rows.map((r, i) => (
              <tr key={r.employeeId ?? i} data-testid={`${TEST_ID}-row-${r.employeeId ?? i}`}>
                <td>{r.employeeCode ?? '—'}</td>
                <td>{r.employeeName ?? '—'}</td>
                <td>{r.departmentName ?? '—'}</td>
                <td className={erp.colRight}>{r.workingDays ?? 0}</td>
                <td className={erp.colRight}>
                  {(r.overtimeHours ?? 0) > 0 ? (r.overtimeHours ?? 0).toFixed(1) : '—'}
                </td>
                <td>
                  <div className={erp.progressBar}>
                    <div
                      className={erp.progressFill}
                      style={{ width: `${Math.min(100, r.attendanceRate ?? 0)}%` }}
                    />
                  </div>
                  <div className={erp.progressLabel}>{Math.round(r.attendanceRate ?? 0)}%</div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    ) : null;

  return (
    <div
      className={erp.voucherListRoot}
      data-voucher-list-page
      data-report-list-page
      data-testid={`${TEST_ID}-list`}
    >
      <LinPageLayout
        kind="report"
        testIdPrefix={TEST_ID}
        pageId={PAGE_ID}
        pageClassName={`${erp.catalogListPage} ${erp.voucherListPage}`}
        header={{
          title: `${labels.title} T${month}/${year}`,
          titleIconClass: 'fas fa-calendar-check',
          pageId: PAGE_ID,
          hint: headerHint,
        }}
        toolbarProps={{
          testIdPrefix: TEST_ID,
          profile: 'report',
          actions: toolbarActions,
        }}
        listTitle={labels.listTitle}
        filters={listFilters}
        listLayoutVariant="erp-filter-bar"
        listHeaderClassName={LIN_ERP_LIST_FILTER_LAYOUT.header}
        listFiltersClassName={LIN_ERP_LIST_FILTER_LAYOUT.filtersHost}
        showTableLoading={showTableLoading}
        skeletonRows={8}
      >
        {listBody}
      </LinPageLayout>
    </div>
  );
};

export default BaoCaoCongPage;
